<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Falling Sand Sandbox</title>
  <style>
    :root {
      color-scheme: dark;
      --panel: #171b23;
      --panel-2: #202631;
      --text: #edf2f7;
      --muted: #98a2b3;
      --accent: #f5c451;
    }

    * {
      box-sizing: border-box;
    }

    html,
    body {
      min-height: 100%;
      margin: 0;
    }

    body {
      display: flex;
      justify-content: center;
      background:
        radial-gradient(circle at 50% 0%, #252d3a 0, #11151c 45%, #090c11 100%);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    main {
      width: max-content;
      max-width: 100%;
      padding: 24px;
      text-align: center;
    }

    h1 {
      margin: 0 0 4px;
      font-size: 26px;
      letter-spacing: 0.02em;
    }

    .subtitle {
      margin: 0 0 16px;
      color: var(--muted);
      font-size: 14px;
    }

    .toolbar {
      width: 560px;
      max-width: none;
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 8px;
      margin: 0 auto 12px;
      padding: 10px;
      border: 1px solid #303846;
      border-radius: 14px;
      background: rgba(23, 27, 35, 0.94);
      box-shadow: 0 12px 35px rgba(0, 0, 0, 0.28);
    }

    button {
      min-height: 38px;
      padding: 8px 13px;
      border: 1px solid #394352;
      border-radius: 9px;
      background: linear-gradient(#29313d, #202630);
      color: #e9eef5;
      font: inherit;
      font-size: 13px;
      font-weight: 700;
      cursor: pointer;
      transition: transform 100ms ease, border-color 100ms ease, box-shadow 100ms ease;
    }

    button:hover {
      transform: translateY(-1px);
      border-color: #596577;
    }

    button:active {
      transform: translateY(1px);
    }

    button.selected {
      border-color: var(--button-color, var(--accent));
      box-shadow:
        0 0 0 2px color-mix(in srgb, var(--button-color, var(--accent)) 34%, transparent),
        inset 0 0 18px color-mix(in srgb, var(--button-color, var(--accent)) 15%, transparent);
    }

    #mat-sand { --button-color: #e8bd54; }
    #mat-water { --button-color: #4aa9ff; }
    #mat-wall { --button-color: #aeb6c3; }
    #mat-acid { --button-color: #7ee34e; }
    #mat-empty { --button-color: #ef7080; }

    #clear {
      margin-left: 5px;
      border-color: #663844;
      background: linear-gradient(#4a2932, #382027);
      color: #ffbdc6;
    }

    .brush-control {
      display: flex;
      align-items: center;
      gap: 8px;
      min-height: 38px;
      padding: 0 9px;
      border: 1px solid #343d4b;
      border-radius: 9px;
      color: var(--muted);
      font-size: 12px;
      font-weight: 700;
    }

    #brush {
      width: 82px;
      accent-color: #e8bd54;
      cursor: pointer;
    }

    .canvas-shell {
      position: relative;
      width: 574px;
      height: 574px;
      margin: auto;
      padding: 7px;
      border: 1px solid #353e4d;
      border-radius: 16px;
      background: linear-gradient(145deg, #222936, #11151c);
      box-shadow:
        0 24px 60px rgba(0, 0, 0, 0.46),
        inset 0 1px rgba(255, 255, 255, 0.04);
    }

    #sand {
      display: block;
      width: 560px;
      height: 560px;
      border-radius: 10px;
      background: #070a0e;
      cursor: crosshair;
      touch-action: none;
      image-rendering: pixelated;
    }

    .hint {
      margin: 11px 0 0;
      color: #7f8999;
      font-size: 12px;
    }
  </style>
</head>
<body>
  <main>
    <h1>Element Sandbox</h1>
    <p class="subtitle">Paint, pour, dissolve, and build.</p>

    <div class="toolbar" aria-label="Sandbox controls">
      <button id="mat-sand" class="selected" type="button">● Sand</button>
      <button id="mat-water" type="button">● Water</button>
      <button id="mat-wall" type="button">■ Wall</button>
      <button id="mat-acid" type="button">● Acid</button>
      <button id="mat-empty" type="button">⌫ Eraser</button>

      <label class="brush-control">
        Brush
        <input id="brush" type="range" min="1" max="6" value="3">
      </label>

      <button id="clear" type="button">Clear</button>
    </div>

    <div class="canvas-shell">
      <canvas id="sand" width="600" height="600" aria-label="Falling sand simulation"></canvas>
    </div>

    <p class="hint">Click and drag to paint. Sand sinks, water flows, and acid erodes walls.</p>
  </main>

  <script>
    (() => {
      "use strict";

      const W = 100;
      const H = 100;
      const SIZE = W * H;

      const EMPTY = 0;
      const SAND = 1;
      const WATER = 2;
      const WALL = 3;
      const ACID = 4;

      const names = ["empty", "sand", "water", "wall", "acid"];
      const codes = Object.freeze({
        empty: EMPTY,
        sand: SAND,
        water: WATER,
        wall: WALL,
        acid: ACID
      });

      const grid = new Uint8Array(SIZE);
      const moved = new Uint8Array(SIZE);

      // Marks liquid displaced upward by a sand swap. It must first escape
      // sideways or downward before it can be displaced upward again.
      const displaced = new Uint8Array(SIZE);

      const canvas = document.getElementById("sand");
      const ctx = canvas.getContext("2d", { alpha: false });
      ctx.imageSmoothingEnabled = false;

      const image = ctx.createImageData(canvas.width, canvas.height);
      const pixels = image.data;
      const scaleX = canvas.width / W;
      const scaleY = canvas.height / H;

      let seed = 0x6d2b79f5;
      let selected = "sand";
      let painting = false;
      let lastPaint = null;

      function random() {
        seed ^= seed << 13;
        seed ^= seed >>> 17;
        seed ^= seed << 5;
        return (seed >>> 0) / 4294967296;
      }

      function index(x, y) {
        return y * W + x;
      }

      function inBounds(x, y) {
        return x >= 0 && x < W && y >= 0 && y < H;
      }

      function moveCell(x1, y1, x2, y2) {
        const from = index(x1, y1);
        const to = index(x2, y2);
        grid[to] = grid[from];
        grid[from] = EMPTY;
        displaced[to] = 0;
        displaced[from] = 0;
        moved[to] = 1;
        moved[from] = 1;
      }

      function swapSandWithLiquid(x, y) {
        if (y + 1 >= H) return false;

        const from = index(x, y);
        const below = index(x, y + 1);
        const liquid = grid[below];

        if ((liquid !== WATER && liquid !== ACID) || displaced[below]) {
          return false;
        }

        grid[below] = SAND;
        grid[from] = liquid;

        // The displaced liquid remains local rather than repeatedly bubbling
        // up through an incoming vertical sand column.
        displaced[from] = 1;
        displaced[below] = 0;
        moved[from] = 1;
        moved[below] = 1;
        return true;
      }

      function updateSand(x, y) {
        if (y + 1 >= H) return;

        const below = grid[index(x, y + 1)];

        if (below === EMPTY) {
          moveCell(x, y, x, y + 1);
          return;
        }

        if (below === WATER || below === ACID) {
          if (swapSandWithLiquid(x, y)) return;
        }

        const first = random() < 0.5 ? -1 : 1;
        for (let attempt = 0; attempt < 2; attempt++) {
          const dx = attempt === 0 ? first : -first;
          const nx = x + dx;
          const ny = y + 1;

          if (nx >= 0 && nx < W && grid[index(nx, ny)] === EMPTY) {
            moveCell(x, y, nx, ny);
            return;
          }
        }
      }

      function updateLiquid(x, y) {
        if (y + 1 < H && grid[index(x, y + 1)] === EMPTY) {
          moveCell(x, y, x, y + 1);
          return;
        }

        if (y + 1 < H) {
          const firstDiagonal = random() < 0.5 ? -1 : 1;
          for (let attempt = 0; attempt < 2; attempt++) {
            const dx = attempt === 0 ? firstDiagonal : -firstDiagonal;
            const nx = x + dx;

            if (nx >= 0 && nx < W && grid[index(nx, y + 1)] === EMPTY) {
              moveCell(x, y, nx, y + 1);
              return;
            }
          }
        }

        const firstSide = random() < 0.5 ? -1 : 1;
        for (let attempt = 0; attempt < 2; attempt++) {
          const dx = attempt === 0 ? firstSide : -firstSide;
          const nx = x + dx;

          if (nx >= 0 && nx < W && grid[index(nx, y)] === EMPTY) {
            moveCell(x, y, nx, y);
            return;
          }
        }
      }

      function dissolveNeighbors(x, y) {
        const neighbors = [
          [x, y + 1],
          [x - 1, y],
          [x + 1, y]
        ];

        if (random() < 0.5) {
          const temp = neighbors[1];
          neighbors[1] = neighbors[2];
          neighbors[2] = temp;
        }

        for (const [nx, ny] of neighbors) {
          if (!inBounds(nx, ny)) continue;
          const i = index(nx, ny);

          if (grid[i] === SAND || grid[i] === WALL) {
            grid[i] = EMPTY;
            displaced[i] = 0;
          }
        }
      }

      function step() {
        moved.fill(0);

        // Bottom-row-up processing prevents a newly moved particle from
        // falling through multiple rows during one simulation step.
        for (let y = H - 1; y >= 0; y--) {
          const leftToRight = random() < 0.5;

          for (let n = 0; n < W; n++) {
            const x = leftToRight ? n : W - 1 - n;
            const i = index(x, y);

            if (moved[i]) continue;

            const material = grid[i];

            if (material === SAND) {
              updateSand(x, y);
            } else if (material === WATER) {
              updateLiquid(x, y);
            } else if (material === ACID) {
              dissolveNeighbors(x, y);
              if (grid[i] === ACID && !moved[i]) {
                updateLiquid(x, y);
              }
            }
          }
        }
      }

      function colorFor(material, x, y) {
        const variation = ((x * 17 + y * 31 + x * y * 3) & 15) - 7;

        switch (material) {
          case SAND:
            return [224 + variation, 177 + variation, 67 + variation / 2];
          case WATER:
            return [30, 123 + variation, 213 + variation];
          case WALL:
            return [112 + variation, 122 + variation, 137 + variation];
          case ACID:
            return [91 + variation, 217 + variation, 62 + variation];
          default:
            return [7, 10, 14];
        }
      }

      function render() {
        for (let y = 0; y < H; y++) {
          const py0 = Math.floor(y * scaleY);
          const py1 = Math.floor((y + 1) * scaleY);

          for (let x = 0; x < W; x++) {
            const px0 = Math.floor(x * scaleX);
            const px1 = Math.floor((x + 1) * scaleX);
            const material = grid[index(x, y)];
            const color = colorFor(material, x, y);

            for (let py = py0; py < py1; py++) {
              let p = (py * canvas.width + px0) * 4;

              for (let px = px0; px < px1; px++) {
                let brightness = 0;

                if (material !== EMPTY) {
                  if (py === py0) brightness += 8;
                  if (px === px0) brightness += 3;
                  if (py === py1 - 1) brightness -= 6;
                }

                pixels[p] = Math.max(0, Math.min(255, color[0] + brightness));
                pixels[p + 1] = Math.max(0, Math.min(255, color[1] + brightness));
                pixels[p + 2] = Math.max(0, Math.min(255, color[2] + brightness));
                pixels[p + 3] = 255;
                p += 4;
              }
            }
          }
        }

        ctx.putImageData(image, 0, 0);
      }

      function setCell(x, y, material) {
        x = Math.trunc(Number(x));
        y = Math.trunc(Number(y));

        if (!inBounds(x, y) || !(material in codes)) return false;

        const i = index(x, y);
        grid[i] = codes[material];
        displaced[i] = 0;
        return true;
      }

      function clearGrid() {
        grid.fill(EMPTY);
        moved.fill(0);
        displaced.fill(0);
        seed = 0x6d2b79f5;
        render();
      }

      window.sim = {
        w: W,
        h: H,

        tick(n = 1) {
          n = Math.max(0, Math.floor(Number(n) || 0));
          for (let i = 0; i < n; i++) step();
          render();
        },

        get(x, y) {
          x = Math.trunc(Number(x));
          y = Math.trunc(Number(y));
          if (!inBounds(x, y)) return "wall";
          return names[grid[index(x, y)]];
        },

        set(x, y, material) {
          const result = setCell(x, y, material);
          render();
          return result;
        },

        clear: clearGrid
      };

      const materialButtons = {
        sand: document.getElementById("mat-sand"),
        water: document.getElementById("mat-water"),
        wall: document.getElementById("mat-wall"),
        acid: document.getElementById("mat-acid"),
        empty: document.getElementById("mat-empty")
      };

      for (const [material, button] of Object.entries(materialButtons)) {
        button.addEventListener("click", () => {
          selected = material;
          for (const other of Object.values(materialButtons)) {
            other.classList.remove("selected");
          }
          button.classList.add("selected");
        });
      }

      document.getElementById("clear").addEventListener("click", clearGrid);

      function pointerToCell(event) {
        const rect = canvas.getBoundingClientRect();
        return {
          x: Math.max(0, Math.min(W - 1, Math.floor((event.clientX - rect.left) / rect.width * W))),
          y: Math.max(0, Math.min(H - 1, Math.floor((event.clientY - rect.top) / rect.height * H)))
        };
      }

      function paintPoint(cx, cy) {
        const radius = Number(document.getElementById("brush").value) - 1;

        for (let dy = -radius; dy <= radius; dy++) {
          for (let dx = -radius; dx <= radius; dx++) {
            if (dx * dx + dy * dy > (radius + 0.45) * (radius + 0.45)) continue;

            const x = cx + dx;
            const y = cy + dy;
            if (inBounds(x, y)) setCell(x, y, selected);
          }
        }
      }

      function paintLine(from, to) {
        const dx = to.x - from.x;
        const dy = to.y - from.y;
        const distance = Math.max(Math.abs(dx), Math.abs(dy), 1);

        for (let i = 0; i <= distance; i++) {
          paintPoint(
            Math.round(from.x + dx * i / distance),
            Math.round(from.y + dy * i / distance)
          );
        }
      }

      canvas.addEventListener("pointerdown", event => {
        event.preventDefault();
        painting = true;
        canvas.setPointerCapture(event.pointerId);
        lastPaint = pointerToCell(event);
        paintPoint(lastPaint.x, lastPaint.y);
        render();
      });

      canvas.addEventListener("pointermove", event => {
        if (!painting) return;
        event.preventDefault();

        const next = pointerToCell(event);
        paintLine(lastPaint, next);
        lastPaint = next;
        render();
      });

      function stopPainting(event) {
        if (!painting) return;
        painting = false;
        lastPaint = null;

        if (event && canvas.hasPointerCapture(event.pointerId)) {
          canvas.releasePointerCapture(event.pointerId);
        }
      }

      canvas.addEventListener("pointerup", stopPainting);
      canvas.addEventListener("pointercancel", stopPainting);

      let previousTime = performance.now();
      let accumulator = 0;
      const stepDuration = 1000 / 45;

      function animate(time) {
        accumulator += Math.min(100, time - previousTime);
        previousTime = time;

        let updates = 0;
        while (accumulator >= stepDuration && updates < 4) {
          step();
          accumulator -= stepDuration;
          updates++;
        }

        render();
        requestAnimationFrame(animate);
      }

      render();
      requestAnimationFrame(animate);
    })();
  </script>
</body>
</html>
